(11, 'MP-04', 'Mantenedor Proteinas 4GNs', '', 'un', NULL, NULL, NULL, '69c7c34c2af6f_1774699340.png', '3058.00', '0.00', '0.00', '0.00', '30.00', '0.00', '0.00', 1000, 'ativo', '2026-03-28 12:02:20', '2026-04-15 11:57:09'),
(12, 'MP - 06220', 'Mantenedor Proteinas 6GNs 220v', 'Construção em Aço inox;\r\nControlador de temperatura digital\r\nControle individual por seção. \r\nTemperatura média de trabalho 65ºC\r\nAjuste de temperatura de 50º a 100ºC\r\nProtege contra odores e contaminações, garantindo hambúrgueres suculentos e seguros\r\nIdeal para manter o padrão em estabelecimentos de fast-food e restaurantes\r\nFechado na parte traseira\r\nPés com regulagem de altura\r\nCuba Gn em aço inox ou Policarbonato;\r\nTensão(v) 220\r\n\r\nMedidas: 720x310x380mm', 'un', NULL, NULL, NULL, '69d36a0be63d2_1775462923.png', '5489.00', '0.00', '0.00', '0.00', '30.00', '2480.80', '3225.04', 0, 'ativo', '2026-04-06 08:08:43', '2026-04-15 11:56:58'),
(13, 'MP - 06110v', 'Mantenedor Proteinas 6GNs 110v', 'Construção em Aço inox; Controlador de temperatura digital Controle individual por seção. Temperatura média de trabalho 65ºC Ajuste de temperatura de 50º a 100ºC Protege contra odores e contaminações, garantindo hambúrgueres suculentos e seguros Ideal para manter o padrão em estabelecimentos de fast-food e restaurantes Fechado na parte traseira Pés com regulagem de altura Cuba Gn em aço inox ou Policarbonato; Tensão(v) 110v Medidas: 720x310x380mm', 'un', NULL, NULL, NULL, '69d36c6d8c376_1775463533.png', '5489.00', '0.00', '0.00', '0.00', '30.00', '0.00', '0.00', 0, 'ativo', '2026-04-06 08:18:53', '2026-04-15 11:56:01'),
(14, 'MP - 08220', 'Mantenedor Proteinas 8GNs 220v', 'Construção em Aço inox; Controlador de temperatura digital Controle individual por seção. Temperatura média de trabalho 65ºC Ajuste de temperatura de 50º a 100ºC Protege contra odores e contaminações, garantindo hambúrgueres suculentos e seguros Ideal para manter o padrão em estabelecimentos de fast-food e restaurantes Fechado na parte traseira Pés com regulagem de altura Cuba Gn em aço inox ou Policarbonato; Tensão(v) 220 Medidas: 930x310x380mm', 'un', NULL, NULL, NULL, '69d36ced06ef9_1775463661.png', '7095.00', '0.00', '0.00', '0.00', '30.00', '0.00', '0.00', 0, 'ativo', '2026-04-06 08:21:01', '2026-04-15 11:55:32'),
(15, 'CF-50', 'CONSERVADOR DE FRITURAS CF-50 - 220', 'Construção em Aço inox;\r\n2 Lâmpadas infravermelho;\r\nCesto Batata removível;\r\nTemperatura média de trabalho 60ºC\r\nGaveta coletora de gordura.\r\nPés com regulagem de altura\r\nBandeja de apoio batatas\r\nTensão(v) 220\r\n500 x 500 x 800', 'un', 1, '', '', '6a098c718f8bf_1779010673.png', '1900.00', '0.00', '0.00', '0.00', '30.00', '0.00', '0.00', 0, 'ativo', '2026-04-15 12:03:43', '2026-05-17 09:37:53'),
(17, 'CF-50 - 110', 'CONSERVADOR DE FRITURAS CF-50 - 110', 'Construção em Aço inox;\r\n2 Lâmpadas infravermelho;\r\nCesto Batata removível;\r\nTemperatura média de trabalho 60ºC\r\nGaveta coletora de gordura.\r\nPés com regulagem de altura\r\nBandeja de apoio batatas\r\nTensão(v) 110\r\nMEDIDA: 500 x 500 x 800', 'un', 1, '', '', '6a098c5606849_1779010646.png', '1900.00', '0.00', '0.00', '0.00', '30.00', '0.00', '0.00', 0, 'ativo', '2026-04-15 12:37:41', '2026-05-17 09:37:26'),
(18, 'CF-21', 'CONSERVADOR DE FRITURAS CF-21 - 220', 'Construção em Aço inox;\r\nLâmpada Infravermelho;\r\nTemperatura média de trabalho 65ºC\r\nPés com regulagem de altura\r\nCuba Gn em aço inox 1/1 x 150 Removível;\r\n\r\n\r\nMEDIDA: 360 x 240 x 700', 'un', NULL, NULL, NULL, '69df885a43c5e_1776257114.jpg', '2200.00', '0.00', '0.00', '0.00', '30.00', '0.00', '0.00', 0, 'ativo', '2026-04-15 12:45:14', '2026-04-15 12:47:50'),
(20, 'CF-21 110', 'CONSERVADOR DE FRITURAS CF- 21 - 110', 'Construção em Aço inox;\r\nLâmpada Infravermelho;\r\nTemperatura média de trabalho 65ºC\r\nPés com regulagem de altura\r\nCuba Gn em aço inox 1/1 x 150 Removível;\r\n\r\n\r\nMEDIDAS: 360 x 240 x 700', 'un', 1, '', '', '69fdb3c0f0529_1778234304.png', '2200.00', '0.00', '0.00', '0.00', '30.00', '0.00', '0.00', 0, 'ativo', '2026-04-15 12:48:52', '2026-05-08 09:58:24'),
