INSERT INTO `produto_categorias` (`id`, `nome`, `descricao`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Cocção', 'A categoria de cocção em uma cozinha industrial refere-se ao setor ou processo técnico de aplicação de calor para transformar alimentos crus em pratos prontos, seguros e palatáveis, operando em larga escala. Esta área é considerada a &quot;espinha dorsal&quot; da produção, onde alimentos, após serem pré-preparados (higienizados e cortados), passam por modificações físicas e químicas para garantir sabor, textura e, fundamentalmente, a eliminação de patógenos.', 'ativo', '2026-05-08 09:58:06', '2026-05-08 09:58:06'),
(2, 'Refrigeração', 'A categoria de refrigeração em uma cozinha industrial é um pilar fundamental para a segurança alimentar, conservação de ingredientes e eficiência operacional. Diferente dos modelos residenciais, esses equipamentos são projetados para uso intenso, alta durabilidade, controle preciso de temperatura e grande volume de armazenamento', 'ativo', '2026-05-08 09:59:22', '2026-05-08 09:59:22'),
(3, 'Mobiliário', 'O mobiliário em aço inox para cozinha industrial da Cozinca foca em soluções sob medida e duráveis, essenciais para a higiene, eficiência e organização em ambientes profissionais, como restaurantes e lanchonetes. Feitos com aço inoxidável de alta qualidade, garantem resistência à corrosão, facilidade de limpeza e conformidade com as normas da vigilância sanitária', 'ativo', '2026-05-08 10:00:01', '2026-05-08 10:00:01');
